public int minChangesToDivideString(String s, int k) {
    int n = s.length();
    if (n % k != 0) return -1;
    int chunkCount = n / k;
    int res = 0;
    for (int i = 0; i < k; ++i) {
        int[] counts = new int[26];
        for (int j = i; j < n; j += k) {
            ++counts[s.charAt(j) - 'a'];
        }
        int maxCount = Arrays.stream(counts).max().getAsInt();
        res += chunkCount - maxCount;
    }
    return res;
}
